etb18 %>% 
  mutate(S1 = haven::as_factor(S1),   # zahlenwerte in S1 mit labels überschreiben 
         m1202 = haven::as_factor(m1202)) %>% # auch für m1202
  count(S1,m1202) %>% 
  flextable()
```

